use crate::model::{AppState, ChatMessage, Role};
use crate::Event;

mod agent;
mod input;
mod queue;
mod slash;

pub(crate) fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

pub(crate) fn strip_tool_markers(content: &str) -> String {
    if let Some(pos) = content.find("TOOL:") {
        let before = &content[..pos];
        return before.trim_end().to_string();
    }
    let mut result = String::new();
    for line in content.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with('{') {
            if let Ok(val) = serde_json::from_str::<serde_json::Value>(trimmed) {
                if val.get("name").is_some() && val.get("arguments").is_some() {
                    continue;
                }
            }
        }
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(line);
    }
    result
}

pub(crate) fn content_has_tool_markers(content: &str) -> bool {
    if content.contains("TOOL:") {
        return true;
    }
    content.lines().any(|line| {
        let trimmed = line.trim();
        if !trimmed.starts_with('{') {
            return false;
        }
        serde_json::from_str::<serde_json::Value>(trimmed)
            .map(|v| v.get("name").is_some() && v.get("arguments").is_some())
            .unwrap_or(false)
    })
}

impl AppState {
    pub fn update(&mut self, event: Event) {
        match event {
            Event::Input(c) => self.push_input(c),
            Event::Backspace => self.pop_input(),
            Event::CursorLeft => self.cursor_left(),
            Event::CursorRight => self.cursor_right(),
            Event::CursorStart => self.cursor_start(),
            Event::CursorEnd => self.cursor_end(),
            Event::DeleteWord => self.delete_word(),
            Event::DeleteToEnd => self.delete_to_end(),
            Event::DeleteToStart => self.delete_to_start(),
            Event::KillChar => self.kill_char(),
            Event::HistoryPrev => self.history_prev(),
            Event::HistoryNext => self.history_next(),
            Event::Undo => self.undo(),
            Event::Redo => self.redo(),
            Event::CursorWordLeft => self.cursor_word_left(),
            Event::CursorWordRight => self.cursor_word_right(),
            Event::Paste(text) => self.paste(&text),
            Event::Submit => self.submit(),
            Event::ScrollUp => {
                if self.messages.is_empty() && !self.turn_active {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_add(1);
            }
            Event::ScrollDown => {
                if self.scroll == 0 {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_sub(1);
            }
            Event::Quit => {}
            Event::Reset => *self = AppState::default(),
            Event::AgentThinking { id } => {
                self.set_thinking(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentThoughtDone { id } => {
                self.add_thought(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolStart { id, name } => {
                self.start_tool(id, name);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolEnd { duration_secs, output } => {
                self.end_tool(duration_secs, output);
                self.ensure_turn_complete_last();
            }
            Event::AgentResponse { id, content } => {
                self.append_response(id, content);
                self.ensure_turn_complete_last();
            }
            Event::AgentTurnComplete { id, duration_secs } => {
                self.complete_turn(id, duration_secs);
                self.ensure_turn_complete_last();
            }
            Event::AgentDone { id } => self.finish_turn(id),
            Event::AgentError { id, message } => {
                self.add_error(id, message);
                self.ensure_turn_complete_last();
            }
            Event::SwitchModel { provider, model } => self.switch_model(provider, model),
            Event::FollowUp => self.queue_follow_up(),
            Event::Abort => self.abort_queue(),
            Event::SpawnAgent => {}
            Event::ToggleExpand => self.toggle_expand_all(),
        }
    }

    fn toggle_expand_all(&mut self) {
        self.all_collapsed = !self.all_collapsed;
        self.messages_changed();
    }

    fn switch_model(&mut self, provider: String, model: String) {
        self.current_provider = provider.clone();
        self.current_model = model.clone();
        self.add_system_msg(format!("Switched to {}/{}", provider, model));
    }

    pub fn peek_queue(&self) -> Option<&(String, String)> {
        self.request_queue.front()
    }

    pub fn pop_queue(&mut self) -> Option<(String, String)> {
        self.request_queue.pop_front()
    }

    fn add_system_msg(&mut self, content: String) {
        self.messages.push(ChatMessage {
            role: Role::System,
            content,
            timestamp: now(),
            id: "system".to_string(),
        });
        self.messages_changed();
    }

    /// Move TurnComplete to the end of messages and bump its timestamp.
    /// Called after every agent event to ensure TurnComplete remains last.
    fn ensure_turn_complete_last(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut tc = self.messages.remove(idx);
            tc.timestamp = now();
            self.messages.push(tc);
            self.messages_changed();
        }
    }
}

use unicode_segmentation::UnicodeSegmentation;
use super::*;

// === Grapheme helpers ===

fn prev_grapheme_boundary(s: &str, pos: usize) -> usize {
    let mut last = 0;
    for (i, _) in s.grapheme_indices(true) {
        if i >= pos { break; }
        last = i;
    }
    last
}

fn next_grapheme_boundary(s: &str, pos: usize) -> usize {
    for (i, _) in s.grapheme_indices(true) {
        if i > pos { return i; }
    }
    s.len()
}

// === Word boundary helpers ===

fn find_word_boundary_left(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] != " " { break; }
        pos = prev;
    }
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] == " " { break; }
        pos = prev;
    }
    pos
}

fn find_word_boundary_right(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    let len = s.len();
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] == " " { break; }
        pos = next;
    }
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] != " " { break; }
        pos = next;
    }
    pos
}

impl AppState {
    pub fn hint_text(&self) -> String {
        let mut parts = Vec::new();
        parts.push("Ctrl+Shift+E=expand/collapse".to_string());
        if self.at_suggestions.is_some() {
            parts.push("Tab=cycle".to_string());
            parts.push("Enter=insert".to_string());
            parts.push("Esc=close".to_string());
        } else if self.turn_active {
            parts.push("Enter=steer".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=abort".to_string());
        } else if !self.input.is_empty() {
            parts.push("Enter=send".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        } else {
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        }
        parts.push("Ctrl+C=quit".to_string());
        parts.join(" | ")
    }

    // === Cursor Movement (grapheme-aware) ===

    pub(crate) fn cursor_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_start(&mut self) {
        if self.cursor_pos != 0 {
            self.cursor_pos = 0;
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_end(&mut self) {
        if self.cursor_pos != self.input.len() {
            self.cursor_pos = self.input.len();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Word Navigation ===

    pub(crate) fn cursor_word_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = find_word_boundary_left(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_word_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = find_word_boundary_right(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Text Editing ===

    pub(crate) fn insert_char(&mut self, c: char) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push(c);
        } else {
            self.input.insert(self.cursor_pos, c);
        }
        self.cursor_pos += c.len_utf8();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_before_cursor(&mut self) {
        if self.cursor_pos > 0 {
            self.push_undo();
            let new_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
            self.input.drain(new_pos..self.cursor_pos);
            self.cursor_pos = new_pos;
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_word(&mut self) {
        if self.cursor_pos == 0 {
            self.input_flash = 3;
            return;
        }
        self.push_undo();
        let start = find_word_boundary_left(&self.input, self.cursor_pos);
        self.input.drain(start..self.cursor_pos);
        self.cursor_pos = start;
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_to_end(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            self.input.truncate(self.cursor_pos);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_to_start(&mut self) {
        if self.cursor_pos > 0 {
            self.push_undo();
            self.input.drain(..self.cursor_pos);
            self.cursor_pos = 0;
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn kill_char(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            let end = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.input.drain(self.cursor_pos..end);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Undo / Redo ===

    fn push_undo(&mut self) {
        self.undo_stack.push((self.input.clone(), self.cursor_pos));
    }

    fn clear_redo(&mut self) {
        self.redo_stack.clear();
    }

    pub(crate) fn undo(&mut self) {
        if let Some((text, pos)) = self.undo_stack.pop() {
            self.redo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    pub(crate) fn redo(&mut self) {
        if let Some((text, pos)) = self.redo_stack.pop() {
            self.undo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    // === Paste ===

    pub(crate) fn paste(&mut self, text: &str) {
        let clean = text
            .replace("\r\n", "")
            .replace('\r', "")
            .replace('\n', "")
            .replace('\t', "    ");
        if clean.is_empty() {
            return;
        }
        self.push_undo();
        self.input.insert_str(self.cursor_pos, &clean);
        self.cursor_pos += clean.len();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    // === Legacy methods ===

    pub(crate) fn push_input(&mut self, c: char) {
        if c == '\t' {
            if self.input.contains('@') || self.at_suggestions.is_some() {
                self.cycle_at_suggestions();
            }
            return;
        }
        self.insert_char(c);
    }

    pub(crate) fn pop_input(&mut self) {
        self.delete_before_cursor();
    }

    pub(crate) fn submit(&mut self) {
        if self.at_suggestions.is_some() {
            self.insert_at_suggestion();
            return;
        }
        if self.input.is_empty() {
            self.input_flash = 3;
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        self.cursor_pos = 0;
        self.history_pos = None;
        self.undo_stack.clear();
        self.redo_stack.clear();
        if content.is_empty() {
            return;
        }
        self.input_history.push(content.clone());
        if let Some(response) = self.handle_slash(&content) {
            self.add_system_msg(response);
            return;
        }
        if self.turn_active {
            self.message_queue.push(crate::model::QueuedMessage {
                content,
                kind: crate::model::QueuedMessageKind::Steering,
            });
            self.scroll = 0;
            self.mark_dirty();
            return;
        }
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    // === Input History ===

    pub(crate) fn history_prev(&mut self) {
        if self.input_history.is_empty() {
            self.input_flash = 3;
            return;
        }
        let pos = match self.history_pos {
            Some(p) if p > 0 => p - 1,
            Some(p) => p,
            None => self.input_history.len() - 1,
        };
        self.history_pos = Some(pos);
        self.input = self.input_history[pos].clone();
        self.cursor_pos = self.input.len();
        self.mark_dirty();
    }

    pub(crate) fn history_next(&mut self) {
        let pos = match self.history_pos {
            Some(p) => p + 1,
            None => {
                self.input_flash = 3;
                return;
            }
        };
        if pos >= self.input_history.len() {
            self.history_pos = None;
            self.input.clear();
            self.cursor_pos = 0;
        } else {
            self.history_pos = Some(pos);
            self.input = self.input_history[pos].clone();
            self.cursor_pos = self.input.len();
        }
        self.mark_dirty();
    }

    // === @-ref suggestions ===

    fn handle_at_trigger(&mut self) {
        if self.input.contains('@') {
            let query = self.input.split('@').last().unwrap_or("").to_string();
            let needs_refresh = self.last_at_query.as_ref() != Some(&query)
                || self.at_suggestions.is_none();
            if needs_refresh {
                self.last_at_query = Some(query.clone());
                self.refresh_at_suggestions();
            }
        } else {
            self.at_suggestions = None;
            self.at_selected = None;
            self.last_at_query = None;
        }
    }

    fn refresh_at_suggestions(&mut self) {
        let query = self.input.split('@').last().unwrap_or("").to_string();
        let mut suggestions = crate::file_refs::complete_at_ref(&self.input, ".", 50);
        if suggestions.len() > 1 && !query.is_empty() {
            let refs: Vec<&str> = suggestions.iter().map(|s| s.as_str()).collect();
            suggestions = crate::fuzzy::fuzzy_filter(&query, &refs, 10)
                .into_iter()
                .map(|s| s.to_string())
                .collect();
        }
        if suggestions.is_empty() {
            suggestions = crate::file_refs::find_files("", ".", 10);
        }
        if suggestions.is_empty() {
            self.at_suggestions = None;
            self.at_selected = None;
            return;
        }
        self.at_suggestions = Some(suggestions);
        self.at_selected = Some(0);
        self.mark_dirty();
    }

    fn cycle_at_suggestions(&mut self) {
        if let Some(suggestions) = self.at_suggestions.as_mut() {
            let idx = self.at_selected.map(|i| (i + 1) % suggestions.len()).unwrap_or(0);
            self.at_selected = Some(idx);
            self.mark_dirty();
        } else {
            self.refresh_at_suggestions();
        }
    }

    fn insert_at_suggestion(&mut self) {
        if let Some(idx) = self.at_selected {
            if let Some(suggestions) = self.at_suggestions.take() {
                if let Some(selected) = suggestions.get(idx) {
                    self.input = crate::file_refs::insert_at_ref(&self.input, selected);
                    self.cursor_pos = self.input.len();
                }
            }
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
        }
    }
}

use crate::labels::{thought_with_time, tool_running, tool_done};
use crate::model::{AppState, ChatMessage, Role};
use super::{content_has_tool_markers, now, strip_tool_markers};

impl AppState {
    pub(crate) fn set_thinking(&mut self, id: String) {
        self.streaming = true;
        self.current_request_id = Some(id);
        self.thinking_started_at = Some(std::time::Instant::now());
        self.turn_active = true;
        self.current_action = Some("Thinking".to_string());
        self.turn_started_at.get_or_insert_with(std::time::Instant::now);
        self.messages_changed();
    }

    pub(crate) fn add_thought(&mut self, id: String) {
        let duration = self.thinking_elapsed_secs().unwrap_or(0.0);
        self.current_action = None;
        self.thinking_started_at = None;
        let mut insert_idx = self.messages.len();
        let thought_content = if let Some(idx) = self.messages.iter().position(|m| m.role == Role::Assistant && m.id == id) {
            let assistant = &self.messages[idx];
            let has_tools = content_has_tool_markers(&assistant.content);
            let stripped = strip_tool_markers(&assistant.content);
            if has_tools && !stripped.trim().is_empty() {
                self.messages.remove(idx);
                insert_idx = idx;
                format!("{}\n{}", thought_with_time(duration), stripped)
            } else {
                insert_idx = idx;
                thought_with_time(duration)
            }
        } else {
            thought_with_time(duration)
        };
        let thought_id = format!("{}#thought.{}", id, self.thought_seq);
        self.thought_seq += 1;
        let thought = ChatMessage {
            role: Role::Thought,
            content: thought_content,
            timestamp: now(),
            id: thought_id,
        };
        self.messages.insert(insert_idx, thought);
        self.messages_changed();
    }

    pub(crate) fn start_tool(&mut self, id: String, name: String) {
        self.current_request_id = Some(id.clone());
        self.current_tool_name = Some(name.clone());
        self.tool_started_at = Some(std::time::Instant::now());
        self.intermediate_step_count += 1;
        self.current_action = Some(format!("Running {}", name));
        let tool_id = format!("tool.{}.{}", id, self.intermediate_step_count);
        self.messages.push(ChatMessage {
            role: Role::Tool,
            content: tool_running(&name),
            timestamp: now(),
            id: tool_id,
        });
        self.messages_changed();
    }

    pub(crate) fn end_tool(&mut self, duration_secs: f64, output: String) {
        self.current_action = None;
        self.tool_started_at = None;
        if let Some(name) = self.current_tool_name.take() {
            if let Some(idx) = self.messages.iter().rposition(|m| {
                m.role == Role::Tool && m.content.contains("⠋ Running ")
            }) {
                if let Some(last) = self.messages.get_mut(idx) {
                    last.content = if output.trim().is_empty() {
                        tool_done(&name, duration_secs)
                    } else {
                        format!("{}\n{}", tool_done(&name, duration_secs), output)
                    };
                    last.timestamp = now();
                }
            }
        }
        self.messages_changed();
    }

    pub(crate) fn append_response(&mut self, id: String, content: String) {
        if let Some(msg) = self.messages.iter_mut().find(|m| m.role == Role::Assistant && m.id == id) {
            if !content.is_empty() {
                msg.content.push_str(&content);
            }
            msg.timestamp = now();
            self.messages_changed();
            return;
        }
        if !content.is_empty() {
            self.messages.push(ChatMessage {
                role: Role::Assistant,
                content,
                timestamp: now(),
                id: id.clone(),
            });
            self.current_request_id = Some(id);
            self.messages_changed();
        }
    }

    pub(crate) fn complete_turn(&mut self, id: String, duration_secs: f64) {
        let content = format!("Turn completed in {:.1}s", duration_secs);
        let ts = now();
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete && m.id == id) {
            self.messages[idx].content = content;
            self.messages[idx].timestamp = ts;
        } else {
            self.messages.push(ChatMessage {
                role: Role::TurnComplete,
                content,
                timestamp: ts,
                id,
            });
        }
        self.messages_changed();
        self.turn_started_at = None;
    }

    pub(crate) fn finish_turn(&mut self, id: String) {
        self.strip_tools_from_assistant();
        self.remove_empty_assistant();
        self.clear_turn_state(&id);
        self.deliver_queued();
        self.maybe_end_streaming();
        self.reorder_agent_after_tools();
        self.move_turn_complete_to_end();
        self.messages_changed();
    }

    fn strip_tools_from_assistant(&mut self) {
        for msg in self.messages.iter_mut() {
            if msg.role == Role::Assistant {
                msg.content = strip_tool_markers(&msg.content);
            }
        }
    }

    fn remove_empty_assistant(&mut self) {
        self.messages.retain(|msg| {
            !(msg.role == Role::Assistant && msg.content.trim().is_empty())
        });
    }

    fn clear_turn_state(&mut self, id: &str) {
        if self.current_request_id.as_deref() == Some(id) {
            self.current_request_id = None;
        }
        self.current_tool_name = None;
        self.current_action = None;
        self.intermediate_step_count = 0;
        self.thought_seq = 0;
        self.turn_active = false;
        self.turn_started_at = None;
        self.inflight = self.inflight.saturating_sub(1);
    }

    fn maybe_end_streaming(&mut self) {
        if self.inflight == 0 && self.request_queue.is_empty() {
            self.streaming = false;
            if self.current_request_id.is_none() {
                self.thinking_started_at = None;
            }
        }
    }

    fn reorder_agent_after_tools(&mut self) {
        let last_assistant = self.messages.iter().rposition(|m| m.role == Role::Assistant);
        let last_tool = self.messages.iter().rposition(|m| m.role == Role::Tool);
        if let (Some(a_idx), Some(t_idx)) = (last_assistant, last_tool) {
            if a_idx < t_idx {
                let mut agent = self.messages.remove(a_idx);
                agent.timestamp = now();
                self.messages.insert(t_idx, agent);
            }
        }
    }

    fn move_turn_complete_to_end(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut turn_complete = self.messages.remove(idx);
            turn_complete.timestamp = now();
            self.messages.push(turn_complete);
        }
    }

    pub(crate) fn add_error(&mut self, id: String, message: String) {
        self.streaming = false;
        let mut error = ChatMessage {
            role: Role::Assistant,
            content: format!("Error: {}", message),
            timestamp: now(),
            id: format!("error.{}", id),
        };
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            error.timestamp = self.messages[idx].timestamp;
            self.messages.insert(idx, error);
        } else {
            self.messages.push(error);
        }
        self.messages_changed();
    }
}

use crate::model::AppState;

impl AppState {
    pub(crate) fn handle_slash(&mut self, content: &str) -> Option<String> {
        match content {
            "/reset" => {
                *self = AppState::default();
                Some("State cleared.".to_string())
            }
            "/help" => Some(self.help_text()),
            "/model" => Some(self.model_usage()),
            "/save" => Some("Usage: /save name".to_string()),
            "/load" => Some("Usage: /load name".to_string()),
            "/delete" => Some("Usage: /delete name".to_string()),
            "/sessions" => Some(self.sessions_list()),
            "/compact" => Some(self.handle_compact(None)),
            _ => self.handle_slash_with_arg(content),
        }
    }

    fn handle_slash_with_arg(&mut self, content: &str) -> Option<String> {
        if let Some(rest) = content.strip_prefix("/model ") {
            return Some(self.handle_model(rest));
        }
        if let Some(name) = content.strip_prefix("/save ") {
            return Some(self.handle_save(name));
        }
        if let Some(name) = content.strip_prefix("/load ") {
            return Some(self.handle_load(name));
        }
        if let Some(name) = content.strip_prefix("/delete ") {
            return Some(self.handle_delete(name));
        }
        if let Some(rest) = content.strip_prefix("/compact ") {
            return Some(self.handle_compact(Some(rest)));
        }
        None
    }

    fn model_usage(&self) -> String {
        format!(
            "Current model: {}/{}. Usage: /model provider/model or /model model",
            self.current_provider, self.current_model
        )
    }

    fn handle_model(&mut self, rest: &str) -> String {
        let rest = rest.trim();
        if rest.is_empty() {
            return self.model_usage();
        }
        let parts: Vec<&str> = rest.split('/').filter(|s| !s.is_empty()).collect();
        match parts.len() {
            2 => {
                self.current_provider = parts[0].to_string();
                self.current_model = parts[1].to_string();
                format!("Switched to {}/{}", self.current_provider, self.current_model)
            }
            1 => {
                self.current_model = parts[0].to_string();
                format!("Switched to {}/{}", self.current_provider, self.current_model)
            }
            _ => self.model_usage(),
        }
    }

    fn handle_save(&self, name: &str) -> String {
        let session = crate::session::Session {
            name: name.to_string(),
            created_at: super::now(),
            updated_at: super::now(),
            messages: self.messages.clone(),
            provider: self.current_provider.clone(),
            model: self.current_model.clone(),
        };
        match crate::session::save(name, &session) {
            Ok(()) => format!("Session '{}' saved.", name),
            Err(e) => format!("Could not save '{}': {}", name, e),
        }
    }

    fn handle_load(&mut self, name: &str) -> String {
        match crate::session::load(name) {
            Ok(session) => {
                self.messages = session.messages;
                self.current_provider = session.provider;
                self.current_model = session.model;
                self.messages_changed();
                format!("Session '{}' loaded.", name)
            }
            Err(_) => format!(
                "Session '{}' not found. Use /sessions to list saved sessions.",
                name
            ),
        }
    }

    fn handle_delete(&self, name: &str) -> String {
        match crate::session::delete(name) {
            Ok(()) => format!("Session '{}' deleted.", name),
            Err(_) => format!(
                "Session '{}' not found. Use /sessions to list saved sessions.",
                name
            ),
        }
    }

    fn sessions_list(&self) -> String {
        match crate::session::list() {
            Ok(sessions) => {
                if sessions.is_empty() {
                    "No saved sessions. Use /save name to create one.".to_string()
                } else {
                    format!("Saved sessions:\n{}", sessions.join("\n"))
                }
            }
            Err(e) => format!("Could not list sessions: {}", e),
        }
    }

    fn handle_compact(&mut self, custom: Option<&str>) -> String {
        let keep = 2000usize;
        let msg = self.compact(keep);
        if let Some(instruction) = custom {
            format!("{} (focus: {})", msg, instruction)
        } else {
            msg
        }
    }

    pub fn help_text(&self) -> String {
        format!(
            "Commands:\n\
            /model [provider/model|model] — switch model (current: {}/{})\n\
            /save name — save current session\n\
            /load name — load a saved session\n\
            /sessions — list saved sessions\n\
            /delete name — delete a saved session\n\
            /compact [prompt] — compact older messages\n\
            /reset — clear all state\n\
            /help — show this help\n\
            Enter — send | Alt+Enter — follow-up | Esc — abort | Ctrl+S — steer",
            self.current_provider, self.current_model
        )
    }
}

use crate::model::{AppState, ChatMessage, Role};
use super::now;

impl AppState {
    pub(crate) fn queue_follow_up(&mut self) {
        if self.input.is_empty() {
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        if content.is_empty() {
            return;
        }
        self.message_queue.push(crate::model::QueuedMessage {
            content,
            kind: crate::model::QueuedMessageKind::FollowUp,
        });
        self.scroll = 0;
        self.mark_dirty();
    }

    pub(crate) fn abort_queue(&mut self) {
        if self.at_suggestions.take().is_some() {
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
            return;
        }
        for msg in self.message_queue.drain(..).rev() {
            if !self.input.is_empty() {
                self.input.push('\n');
            }
            self.input.push_str(&msg.content);
        }
        self.mark_dirty();
    }

    pub(crate) fn deliver_queued(&mut self) {
        if self.message_queue.is_empty() {
            return;
        }
        if self.try_deliver_steering() {
            return;
        }
        self.try_deliver_follow_up();
    }

    fn try_deliver_steering(&mut self) -> bool {
        let steering: Vec<_> = self.message_queue.iter().enumerate()
            .filter(|(_, m)| m.kind == crate::model::QueuedMessageKind::Steering)
            .map(|(i, _)| i)
            .collect();
        if steering.is_empty() {
            return false;
        }
        let idx = steering[0];
        let msg = self.message_queue.remove(idx);
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: msg.content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((msg.content, id));
        self.scroll = 0;
        self.messages_changed();
        true
    }

    fn try_deliver_follow_up(&mut self) {
        let follow_up: Vec<_> = self.message_queue.iter().enumerate()
            .filter(|(_, m)| m.kind == crate::model::QueuedMessageKind::FollowUp)
            .map(|(i, _)| i)
            .collect();
        if follow_up.is_empty() {
            return;
        }
        let idx = follow_up[0];
        let msg = self.message_queue.remove(idx);
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: msg.content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((msg.content, id));
        self.scroll = 0;
        self.messages_changed();
    }
}

//! Model — Application State (mutable borrow, no cloning per event)
use crate::snapshot::Snapshot;
use crate::ui::elements::Element;


const SPINNER_CHARS: &[char] = &['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠹', '⠸', '⠴', '⠼'];
const SPINNER_FRAMES: u32 = 12;

/// A viewport into the element cache — elements plus how many
/// lines to skip from the top of the first element.
#[derive(Clone, Copy)]
pub struct VisibleRegion<'a> {
    pub elements: &'a [Element],
    pub skip_lines: usize,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum QueuedMessageKind {
    Steering,
    FollowUp,
}

#[derive(Clone, Debug)]
pub struct QueuedMessage {
    pub content: String,
    pub kind: QueuedMessageKind,
}

#[derive(Clone)]
pub struct AppState {
    pub messages: Vec<ChatMessage>,
    pub input: String,
    /// Cursor position in input (0 = before first char)
    pub cursor_pos: usize,
    pub streaming: bool,
    pub scroll: usize,
    pub thinking_started_at: Option<std::time::Instant>,
    pub request_queue: std::collections::VecDeque<(String, String)>,
    pub message_queue: Vec<QueuedMessage>,
    pub next_id: u64,
    pub current_request_id: Option<String>,
    pub turn_started_at: Option<std::time::Instant>,
    pub current_tool_name: Option<String>,
    pub tool_started_at: Option<std::time::Instant>,
    pub intermediate_step_count: usize,
    pub animation_frame: u32,
    pub turn_active: bool,
    pub current_action: Option<String>,
    pub current_provider: String,
    pub current_model: String,

    /// Number of commands sent to agent but not yet completed
    pub inflight: usize,
    /// Monotonic counter — increments on every snapshot sent to render actor
    pub render_generation: u64,
    /// @-ref file lookup suggestions
    pub at_suggestions: Option<Vec<String>>,
    /// Selected index in @-ref suggestions
    pub at_selected: Option<usize>,
    /// Last @-ref query to avoid redundant filesystem calls
    pub last_at_query: Option<String>,
    /// Global collapse flag — when true, ALL thoughts/tools render collapsed.
    /// New elements automatically respect this setting.
    pub all_collapsed: bool,
    pub(crate) thought_seq: u64,
    pub(crate) input_history: Vec<String>,
    pub(crate) history_pos: Option<usize>,
    pub(crate) undo_stack: Vec<(String, usize)>,
    pub(crate) redo_stack: Vec<(String, usize)>,
    pub input_flash: u8,
    pub placeholder: String,
    element_count: usize,
    elements_cache: Vec<Element>,
    line_counts: Vec<usize>,
    total_lines: usize,
    dirty: bool,
    message_gen: u64,
    cached_gen: u64,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            messages: Vec::new(), input: String::new(), cursor_pos: 0,
            streaming: false, scroll: 0, thinking_started_at: None,
            request_queue: std::collections::VecDeque::new(),
            message_queue: Vec::new(), next_id: 0,
            current_request_id: None, turn_started_at: None,
            current_tool_name: None, tool_started_at: None,
            intermediate_step_count: 0, animation_frame: 0,
            turn_active: false, current_action: None,
            current_provider: "mock".into(), current_model: "echo".into(),
            inflight: 0, render_generation: 0,
            at_suggestions: None, at_selected: None, last_at_query: None,
            all_collapsed: false, thought_seq: 0,
            input_history: Vec::new(), history_pos: None,
            undo_stack: Vec::new(), redo_stack: Vec::new(),
            input_flash: 0, placeholder: "Type a message to start...".into(),
            element_count: 0, elements_cache: Vec::new(),
            line_counts: Vec::new(), total_lines: 0,
            dirty: true, message_gen: 1, cached_gen: 0,
        }
    }
}

impl AppState {
    pub fn thinking_elapsed_secs(&self) -> Option<f64> {
        self.thinking_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn turn_elapsed_secs(&self) -> Option<f64> {
        self.turn_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn tool_elapsed_secs(&self) -> Option<f64> {
        self.tool_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    /// Braille spinner frame (12-frame cycle)
    pub fn spinner_frame(&self) -> char {
        SPINNER_CHARS[(self.animation_frame % SPINNER_FRAMES) as usize]
    }

    pub fn next_id(&mut self) -> String {
        let id = format!("req.{}", self.next_id);
        self.next_id += 1;
        id
    }

    pub(crate) fn mark_dirty(&mut self) {
        self.dirty = true;
    }

    pub(crate) fn messages_changed(&mut self) {
        self.message_gen = self.message_gen.wrapping_add(1);
        self.dirty = true;
    }

    pub fn cache_generation(&self) -> u64 {
        self.message_gen
    }

    /// Rebuild cache only when messages changed — O(n) but gated
    pub fn ensure_fresh(&mut self) {
        if self.dirty && self.message_gen != self.cached_gen {
            self.elements_cache = crate::ui::LazyCache::rebuild(self);
            self.element_count = self.elements_cache.len();
            self.line_counts = self.elements_cache.iter().map(|e| e.line_count()).collect();
            self.total_lines = self.line_counts.iter().sum();
            self.cached_gen = self.message_gen;
        }
        self.dirty = false;
    }

    /// Visible elements slice — O(1), zero allocation
    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        if self.elements_cache.is_empty() {
            return &[];
        }
        let start = skip.min(self.element_count).min(self.elements_cache.len());
        let end = (start + take).min(self.element_count).min(self.elements_cache.len());
        &self.elements_cache[start..end]
    }

    pub fn count(&self) -> usize {
        self.element_count.max(self.elements_cache.len())
    }

    pub fn element_count(&self) -> usize {
        self.element_count
    }

    pub fn total_lines(&self) -> usize {
        self.total_lines
    }

    pub fn elements_cache(&self) -> &[Element] {
        &self.elements_cache
    }

    pub fn tick_animation(&mut self) {
        let mut changed = false;
        if self.turn_active {
            self.animation_frame = self.animation_frame.wrapping_add(1);
            changed = true;
        }
        if self.input_flash > 0 {
            self.input_flash -= 1;
            changed = true;
        }
        if changed {
            self.dirty = true;
        }
    }

    /// Build an immutable Snapshot for the render actor.
    /// The event loop calls this after ensure_fresh(); the render
    /// actor receives it via channel and draws without touching state.
    pub fn snapshot(&self) -> Snapshot {
        Snapshot {
            elements: self.elements_cache.clone(),
            line_counts: self.line_counts.clone(),
            total_lines: self.total_lines,
            input: self.input.clone(),
            cursor_pos: self.cursor_pos,
            hint_text: self.hint_text(),
            at_suggestions: self.at_suggestions.clone(),
            at_selected: self.at_selected,
            turn_active: self.turn_active,
            input_flash: self.input_flash,
            placeholder: self.placeholder.clone(),
            spinner_frame: self.spinner_frame(),
            scroll: self.scroll,
            turn_elapsed_secs: self.turn_elapsed_secs(),
            provider: self.current_provider.clone(),
            model: self.current_model.clone(),
            queue_count: self.message_queue.len() + self.request_queue.len(),
        }
    }

    pub fn is_dirty(&self) -> bool {
        self.dirty
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements_cache.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements_cache.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements_cache[start_idx..end_idx.min(self.elements_cache.len())],
            skip_lines,
        }
    }

    pub fn total_tokens(&self) -> usize {
        self.messages.iter().map(|m| crate::tokens::estimate_tokens(&m.content)).sum()
    }

    pub fn compact(&mut self, keep_recent_tokens: usize) -> String {
        let total = self.total_tokens();
        if total <= keep_recent_tokens {
            return format!("Session has {} tokens, no compaction needed", total);
        }
        let mut accumulated = 0usize;
        let mut cut_idx = 0usize;
        for (i, msg) in self.messages.iter().enumerate().rev() {
            accumulated += crate::tokens::estimate_tokens(&msg.content);
            if accumulated >= keep_recent_tokens {
                cut_idx = i;
                break;
            }
        }
        while cut_idx < self.messages.len() {
            match self.messages[cut_idx].role {
                Role::User | Role::Assistant => break,
                _ => cut_idx += 1,
            }
        }
        if cut_idx == 0 {
            return "Cannot compact: all messages are recent".to_string();
        }
        let removed_count = cut_idx;
        self.messages.drain(..cut_idx);
        let summary = format!("[Compacted: {} earlier messages removed, keeping ~{} tokens]", removed_count, keep_recent_tokens);
        self.messages.insert(0, ChatMessage {
            role: Role::System,
            content: summary.clone(),
            timestamp: now(),
            id: "compaction".to_string(),
        });
        self.messages_changed();
        summary
    }
}

pub fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

