use crate::labels::{thought_with_time, tool_running, tool_done};
use crate::model::{AppState, ChatMessage, Role};
use super::{content_has_tool_markers, now, strip_tool_markers};

impl AppState {
    pub(crate) fn set_thinking(&mut self, id: String) {
        self.set_streaming(true);
        self.set_current_request_id(Some(id));
        self.set_thinking_started_at(Some(std::time::Instant::now()));
        self.set_turn_active(true);
        self.set_current_action(Some("Thinking".to_string()));
        self.agent.turn_started_at.get_or_insert_with(std::time::Instant::now);
        self.messages_changed();
    }

    pub(crate) fn add_thought(&mut self, id: String) {
        let duration = self.thinking_elapsed_secs().unwrap_or(0.0);
        self.set_current_action(None);
        self.set_thinking_started_at(None);
        let mut insert_idx = self.messages_len();
        let thought_content = if let Some(idx) = self.messages_position(|m| m.role == Role::Assistant && m.id == id) {
            let assistant = self.messages_get_mut(idx).unwrap();
            let has_tools = content_has_tool_markers(&assistant.content);
            let stripped = strip_tool_markers(&assistant.content);
            if has_tools && !stripped.trim().is_empty() {
                self.messages_remove(idx);
                insert_idx = idx;
                format!("{}\n{}", thought_with_time(duration), stripped)
            } else {
                insert_idx = idx;
                thought_with_time(duration)
            }
        } else {
            thought_with_time(duration)
        };
        let thought_id = format!("{}#thought.{}", id, self.thought_seq());
        self.thought_seq_increment();
        let thought = ChatMessage {
            role: Role::Thought,
            content: thought_content,
            timestamp: now(),
            id: thought_id,
        };
        self.messages_insert(insert_idx, thought);
        self.messages_changed();
    }

    pub(crate) fn start_tool(&mut self, id: String, name: String) {
        self.set_current_request_id(Some(id));
        self.set_current_tool_name(Some(name.clone()));
        self.set_tool_started_at(Some(std::time::Instant::now()));
        self.intermediate_step_count_increment();
        self.set_current_action(Some(format!("Running {}", name)));
        let tool_id = format!("tool.{}.{}", id, self.agent.intermediate_step_count);
        self.messages_push(ChatMessage {
            role: Role::Tool,
            content: tool_running(&name),
            timestamp: now(),
            id: tool_id,
        });
        self.messages_changed();
    }

    pub(crate) fn end_tool(&mut self, duration_secs: f64, output: String) {
        self.set_current_action(None);
        self.set_tool_started_at(None);
        if let Some(name) = self.agent.current_tool_name.take() {
            if let Some(idx) = self.messages_rposition(|m| {
                m.role == Role::Tool && m.content.contains("⠋ Running ")
            }) {
                if let Some(last) = self.messages_get_mut(idx) {
                    last.content = if output.trim().is_empty() {
                        tool_done(&name, duration_secs)
                    } else {
                        format!("{}\n{}", tool_done(&name, duration_secs), output)
                    };
                    last.timestamp = now();
                }
            }
        }
        self.messages_changed();
    }

    pub(crate) fn append_response(&mut self, id: String, content: String) {
        // O(1) lookup using cached last_assistant_index
        if let Some(idx) = self.agent.last_assistant_index {
            if let Some(msg) = self.messages_get_mut(idx) {
                if msg.role == Role::Assistant && msg.id == id {
                    if !content.is_empty() {
                        msg.content.push_str(&content);
                    }
                    msg.timestamp = now();
                    self.messages_changed();
                    return;
                }
            }
        }
        // Fallback: search for existing message
        if let Some(idx) = self.messages_position(|m| m.role == Role::Assistant && m.id == id) {
            if let Some(msg) = self.messages_get_mut(idx) {
                if !content.is_empty() {
                    msg.content.push_str(&content);
                }
                msg.timestamp = now();
                self.agent.last_assistant_index = Some(idx);
                self.messages_changed();
                return;
            }
        }
        // New message
        if !content.is_empty() {
            let idx = self.messages_len();
            self.messages_push(ChatMessage {
                role: Role::Assistant,
                content,
                timestamp: now(),
                id: id.clone(),
            });
            self.set_current_request_id(Some(id));
            self.agent.last_assistant_index = Some(idx);
            self.messages_changed();
        }
    }

    pub(crate) fn complete_turn(&mut self, id: String, duration_secs: f64) {
        let content = format!("Turn completed in {:.1}s", duration_secs);
        let ts = now();
        if let Some(idx) = self.messages_position(|m| m.role == Role::TurnComplete && m.id == id) {
            if let Some(msg) = self.messages_get_mut(idx) {
                msg.content = content;
                msg.timestamp = ts;
            }
        } else {
            self.messages_push(ChatMessage {
                role: Role::TurnComplete,
                content,
                timestamp: ts,
                id,
            });
        }
        self.messages_changed();
        self.set_turn_started_at(None);
    }

    pub(crate) fn finish_turn(&mut self, id: String) {
        self.strip_tools_from_assistant();
        self.remove_empty_assistant();
        self.clear_turn_state(&id);
        self.deliver_queued();
        self.maybe_end_streaming();
        self.reorder_agent_after_tools();
        self.move_turn_complete_to_end();
        self.messages_changed();
    }

    fn strip_tools_from_assistant(&mut self) {
        for msg in self.messages_iter_mut() {
            if msg.role == Role::Assistant {
                msg.content = strip_tool_markers(&msg.content);
            }
        }
    }

    fn remove_empty_assistant(&mut self) {
        self.messages_retain(|msg| {
            !(msg.role == Role::Assistant && msg.content.trim().is_empty())
        });
    }

    fn clear_turn_state(&mut self, id: &str) {
        if self.agent.current_request_id.as_deref() == Some(id) {
            self.set_current_request_id(None);
        }
        self.set_current_tool_name(None);
        self.set_current_action(None);
        self.set_intermediate_step_count(0);
        self.set_thought_seq(0);
        self.set_turn_active(false);
        self.set_turn_started_at(None);
        self.inflight_decrement();
    }

    fn maybe_end_streaming(&mut self) {
        if self.agent.inflight == 0 && self.agent.request_queue.is_empty() {
            self.set_streaming(false);
            if self.agent.current_request_id.is_none() {
                self.set_thinking_started_at(None);
            }
        }
    }

    fn reorder_agent_after_tools(&mut self) {
        let last_assistant = self.messages_rposition(|m| m.role == Role::Assistant);
        let last_tool = self.messages_rposition(|m| m.role == Role::Tool);
        if let (Some(a_idx), Some(t_idx)) = (last_assistant, last_tool) {
            if a_idx < t_idx {
                let mut agent = self.messages_remove(a_idx);
                agent.timestamp = now();
                self.messages_insert(t_idx, agent);
                // Update cached index
                if self.agent.last_assistant_index == Some(a_idx) {
                    self.agent.last_assistant_index = Some(t_idx);
                }
            }
        }
    }

    fn move_turn_complete_to_end(&mut self) {
        if let Some(idx) = self.messages_position(|m| m.role == Role::TurnComplete) {
            let mut turn_complete = self.messages_remove(idx);
            turn_complete.timestamp = now();
            self.messages_push(turn_complete);
            // Update cached index if needed
            if let Some(last_idx) = self.agent.last_assistant_index {
                if last_idx >= idx {
                    self.agent.last_assistant_index = Some(last_idx.saturating_sub(1));
                }
            }
        }
    }

    pub(crate) fn add_error(&mut self, id: String, message: String) {
        self.set_streaming(false);
        let mut error = ChatMessage {
            role: Role::Assistant,
            content: format!("Error: {}", message),
            timestamp: now(),
            id: format!("error.{}", id),
        };
        if let Some(idx) = self.messages_position(|m| m.role == Role::TurnComplete) {
            error.timestamp = self.messages_get_mut(idx).map(|m| m.timestamp).unwrap_or(now());
            self.messages_insert(idx, error);
        } else {
            self.messages_push(error);
        }
        self.messages_changed();
    }
}

use unicode_segmentation::UnicodeSegmentation;
use super::*;

// === Grapheme helpers ===

fn prev_grapheme_boundary(s: &str, pos: usize) -> usize {
    let mut last = 0;
    for (i, _) in s.grapheme_indices(true) {
        if i >= pos {
            break;
        }
        last = i;
    }
    last
}

fn next_grapheme_boundary(s: &str, pos: usize) -> usize {
    for (i, _) in s.grapheme_indices(true) {
        if i > pos {
            return i;
        }
    }
    s.len()
}

// === Word boundary helpers ===

fn find_word_boundary_left(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] != " " {
            break;
        }
        pos = prev;
    }
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] == " " {
            break;
        }
        pos = prev;
    }
    pos
}

fn find_word_boundary_right(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    let len = s.len();
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] == " " {
            break;
        }
        pos = next;
    }
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] != " " {
            break;
        }
        pos = next;
    }
    pos
}

impl AppState {
    pub fn hint_text(&self) -> String {
        let mut parts = Vec::new();
        parts.push("Ctrl+Shift+E=expand/collapse".to_string());
        if self.input.at_suggestions.is_some() {
            parts.push("Tab=cycle".to_string());
            parts.push("Enter=insert".to_string());
            parts.push("Esc=close".to_string());
        } else if self.agent.turn_active {
            parts.push("Enter=steer".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=abort".to_string());
        } else if !self.input.input.is_empty() {
            parts.push("Enter=send".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        } else {
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        }
        parts.push("Ctrl+C=quit".to_string());
        parts.join(" | ")
    }

    // === Cursor Movement (grapheme-aware) ===

    pub(crate) fn cursor_left(&mut self) {
        if self.input.cursor_pos > 0 {
            self.input.cursor_pos = prev_grapheme_boundary(&self.input.input, self.input.cursor_pos);
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn cursor_right(&mut self) {
        if self.input.cursor_pos < self.input.input.len() {
            self.input.cursor_pos = next_grapheme_boundary(&self.input.input, self.input.cursor_pos);
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn cursor_start(&mut self) {
        if self.input.cursor_pos != 0 {
            self.input.cursor_pos = 0;
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn cursor_end(&mut self) {
        if self.input.cursor_pos != self.input.input.len() {
            self.input.cursor_pos = self.input.input.len();
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    // === Word Navigation ===

    pub(crate) fn cursor_word_left(&mut self) {
        if self.input.cursor_pos > 0 {
            self.input.cursor_pos = find_word_boundary_left(&self.input.input, self.input.cursor_pos);
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn cursor_word_right(&mut self) {
        if self.input.cursor_pos < self.input.input.len() {
            self.input.cursor_pos = find_word_boundary_right(&self.input.input, self.input.cursor_pos);
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    // === Text Editing ===

    pub(crate) fn insert_char(&mut self, c: char) {
        self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
        if self.input.cursor_pos == self.input.input.len() {
            self.input.input.push(c);
        } else {
            self.input.input.insert(self.input.cursor_pos, c);
        }
        self.input.cursor_pos += c.len_utf8();
        self.input.redo_stack.clear();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_before_cursor(&mut self) {
        if self.input.cursor_pos > 0 {
            self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
            let new_pos = prev_grapheme_boundary(&self.input.input, self.input.cursor_pos);
            self.input.input.drain(new_pos..self.input.cursor_pos);
            self.input.cursor_pos = new_pos;
            self.input.redo_stack.clear();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn delete_word(&mut self) {
        if self.input.cursor_pos == 0 {
            self.input.input_flash = 3;
            return;
        }
        self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
        let start = find_word_boundary_left(&self.input.input, self.input.cursor_pos);
        self.input.input.drain(start..self.input.cursor_pos);
        self.input.cursor_pos = start;
        self.input.redo_stack.clear();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_to_end(&mut self) {
        if self.input.cursor_pos < self.input.input.len() {
            self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
            self.input.input.truncate(self.input.cursor_pos);
            self.input.redo_stack.clear();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn delete_to_start(&mut self) {
        if self.input.cursor_pos > 0 {
            self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
            self.input.input.drain(..self.input.cursor_pos);
            self.input.cursor_pos = 0;
            self.input.redo_stack.clear();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    pub(crate) fn kill_char(&mut self) {
        if self.input.cursor_pos < self.input.input.len() {
            self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
            let end = next_grapheme_boundary(&self.input.input, self.input.cursor_pos);
            self.input.input.drain(self.input.cursor_pos..end);
            self.input.redo_stack.clear();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input.input_flash = 3;
        }
    }

    // === Undo / Redo ===

    pub(crate) fn undo(&mut self) {
        if let Some((text, pos)) = self.input.undo_stack.pop() {
            self.input.redo_stack.push((self.input.input.clone(), self.input.cursor_pos));
            self.input.input = text;
            self.input.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    pub(crate) fn redo(&mut self) {
        if let Some((text, pos)) = self.input.redo_stack.pop() {
            self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
            self.input.input = text;
            self.input.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    // === Paste ===

    pub(crate) fn paste(&mut self, text: &str) {
        let clean = text
            .replace("\r\n", "")
            .replace('\r', "")
            .replace('\n', "")
            .replace('\t', "    ");
        if clean.is_empty() {
            return;
        }
        self.input.undo_stack.push((self.input.input.clone(), self.input.cursor_pos));
        self.input.input.insert_str(self.input.cursor_pos, &clean);
        self.input.cursor_pos += clean.len();
        self.input.redo_stack.clear();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    // === Legacy methods ===

    pub(crate) fn push_input(&mut self, c: char) {
        if c == '\t' {
            if self.input.input.contains('@') || self.input.at_suggestions.is_some() {
                self.cycle_at_suggestions();
            }
            return;
        }
        self.insert_char(c);
    }

    pub(crate) fn pop_input(&mut self) {
        self.delete_before_cursor();
    }

    pub(crate) fn submit(&mut self) {
        if self.input.at_suggestions.is_some() {
            self.insert_at_suggestion();
            return;
        }
        if self.input.input.is_empty() {
            self.input.input_flash = 3;
            return;
        }
        let content = std::mem::take(&mut self.input.input).trim().to_string();
        self.input.cursor_pos = 0;
        self.input.history_pos = None;
        self.input.undo_stack.clear();
        self.input.redo_stack.clear();
        if content.is_empty() {
            return;
        }
        self.input.input_history.push(content.clone());
        if let Some(response) = self.handle_slash(&content) {
            self.add_system_msg(response);
            return;
        }
        if self.agent.turn_active {
            self.agent.message_queue.push(crate::model::QueuedMessage {
                content,
                kind: crate::model::QueuedMessageKind::Steering,
            });
            self.chat.scroll = 0;
            self.mark_dirty();
            return;
        }
        let id = self.next_id();
        self.chat.messages.push(crate::model::ChatMessage {
            role: crate::model::Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.agent.request_queue.push_back((content, id));
        self.chat.scroll = 0;
        self.messages_changed();
    }

    // === Input History ===

    pub(crate) fn history_prev(&mut self) {
        if self.input.input_history.is_empty() {
            self.input.input_flash = 3;
            return;
        }
        let pos = match self.input.history_pos {
            Some(p) if p > 0 => p - 1,
            Some(p) => p,
            None => self.input.input_history.len() - 1,
        };
        self.input.history_pos = Some(pos);
        self.input.input = self.input.input_history[pos].clone();
        self.input.cursor_pos = self.input.input.len();
        self.mark_dirty();
    }

    pub(crate) fn history_next(&mut self) {
        let pos = match self.input.history_pos {
            Some(p) => p + 1,
            None => {
                self.input.input_flash = 3;
                return;
            }
        };
        if pos >= self.input.input_history.len() {
            self.input.history_pos = None;
            self.input.input.clear();
            self.input.cursor_pos = 0;
        } else {
            self.input.history_pos = Some(pos);
            self.input.input = self.input.input_history[pos].clone();
            self.input.cursor_pos = self.input.input.len();
        }
        self.mark_dirty();
    }

    // === @-ref suggestions ===

    fn handle_at_trigger(&mut self) {
        if self.input.input.contains('@') {
            let query = self.input.input.split('@').last().unwrap_or("").to_string();
            let needs_refresh =
                self.input.last_at_query.as_ref() != Some(&query) || self.input.at_suggestions.is_none();
            if needs_refresh {
                self.input.last_at_query = Some(query.clone());
                self.refresh_at_suggestions();
            }
        } else {
            self.input.at_suggestions = None;
            self.input.at_selected = None;
            self.input.last_at_query = None;
        }
    }

    fn refresh_at_suggestions(&mut self) {
        let query = self.input.input.split('@').last().unwrap_or("").to_string();
        let mut suggestions = crate::file_refs::complete_at_ref(&self.input.input, ".", 50);
        if suggestions.len() > 1 && !query.is_empty() {
            let refs: Vec<&str> = suggestions.iter().map(|s| s.as_str()).collect();
            suggestions = crate::fuzzy::fuzzy_filter(&query, &refs, 10)
                .into_iter()
                .map(|s| s.to_string())
                .collect();
        }
        if suggestions.is_empty() {
            suggestions = crate::file_refs::find_files("", ".", 10);
        }
        if suggestions.is_empty() {
            self.input.at_suggestions = None;
            self.input.at_selected = None;
            return;
        }
        self.input.at_suggestions = Some(suggestions);
        self.input.at_selected = Some(0);
        self.mark_dirty();
    }

    fn cycle_at_suggestions(&mut self) {
        if let Some(suggestions) = self.input.at_suggestions.as_mut() {
            let idx = self
                .input
                .at_selected
                .map(|i| (i + 1) % suggestions.len())
                .unwrap_or(0);
            self.input.at_selected = Some(idx);
            self.mark_dirty();
        } else {
            self.refresh_at_suggestions();
        }
    }

    fn insert_at_suggestion(&mut self) {
        if let Some(idx) = self.input.at_selected {
            if let Some(suggestions) = self.input.at_suggestions.take() {
                if let Some(selected) = suggestions.get(idx) {
                    self.input.input = crate::file_refs::insert_at_ref(&self.input.input, selected);
                    self.input.cursor_pos = self.input.input.len();
                }
            }
            self.input.at_selected = None;
            self.input.last_at_query = None;
            self.mark_dirty();
        }
    }
}

