//! Model structs — InputState, ChatHistory, AgentState, UiState
use crate::snapshot::Snapshot;
use crate::ui::elements::Element;
use super::types::{ChatMessage, QueuedMessage};
use std::collections::VecDeque;

// ============================================================================
// Input State
// ============================================================================

/// Input state — text editing, cursor, undo/redo, @-ref suggestions
#[derive(Clone, Debug)]
pub struct InputState {
    pub input: String,
    pub cursor_pos: usize,
    pub input_flash: u8,
    pub input_history: Vec<String>,
    pub history_pos: Option<usize>,
    pub undo_stack: Vec<(String, usize)>,
    pub redo_stack: Vec<(String, usize)>,
    pub at_suggestions: Option<Vec<String>>,
    pub at_selected: Option<usize>,
    pub last_at_query: Option<String>,
}

impl Default for InputState {
    fn default() -> Self {
        Self {
            input: String::new(),
            cursor_pos: 0,
            input_flash: 0,
            input_history: Vec::new(),
            history_pos: None,
            undo_stack: Vec::new(),
            redo_stack: Vec::new(),
            at_suggestions: None,
            at_selected: None,
            last_at_query: None,
        }
    }
}

// ============================================================================
// Chat History
// ============================================================================

/// Chat history — messages, scroll, element cache
#[derive(Clone)]
pub struct ChatHistory {
    pub messages: Vec<ChatMessage>,
    pub scroll: usize,
    pub placeholder: String,
    pub element_count: usize,
    pub elements_cache: Vec<Element>,
    pub line_counts: Vec<usize>,
    pub total_lines: usize,
    pub dirty: bool,
    pub message_gen: u64,
    pub cached_gen: u64,
}

impl Default for ChatHistory {
    fn default() -> Self {
        Self {
            messages: Vec::new(),
            scroll: 0,
            placeholder: "Type a message to start...".into(),
            element_count: 0,
            elements_cache: Vec::new(),
            line_counts: Vec::new(),
            total_lines: 0,
            dirty: true,
            message_gen: 1,
            cached_gen: 0,
        }
    }
}

// ============================================================================
// Agent State
// ============================================================================

/// Agent state — streaming, turn lifecycle, queues, tool execution
#[derive(Clone)]
pub struct AgentState {
    pub streaming: bool,
    pub turn_active: bool,
    pub inflight: usize,
    pub request_queue: VecDeque<(String, String)>,
    pub message_queue: Vec<QueuedMessage>,
    pub next_id: u64,
    pub current_request_id: Option<String>,
    pub current_tool_name: Option<String>,
    pub tool_started_at: Option<std::time::Instant>,
    pub thinking_started_at: Option<std::time::Instant>,
    pub turn_started_at: Option<std::time::Instant>,
    pub intermediate_step_count: usize,
    pub thought_seq: u64,
    pub current_action: Option<String>,
    /// Cached index of last assistant message — O(1) lookup for append_response
    pub last_assistant_index: Option<usize>,
}

impl Default for AgentState {
    fn default() -> Self {
        Self {
            streaming: false,
            turn_active: false,
            inflight: 0,
            request_queue: VecDeque::new(),
            message_queue: Vec::new(),
            next_id: 0,
            current_request_id: None,
            current_tool_name: None,
            tool_started_at: None,
            thinking_started_at: None,
            turn_started_at: None,
            intermediate_step_count: 0,
            thought_seq: 0,
            current_action: None,
            last_assistant_index: None,
        }
    }
}

