/// Main application state — composed from focused sub-structs
#[derive(Clone)]
pub struct AppState {
    pub input: InputState,
    pub chat: ChatHistory,
    pub agent: AgentState,
    pub ui: UiState,
    /// Model configuration (kept at top level for easy access)
    pub current_provider: String,
    pub current_model: String,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            input: InputState::default(),
            chat: ChatHistory::default(),
            agent: AgentState::default(),
            ui: UiState::default(),
            current_provider: "mock".into(),
            current_model: "echo".into(),
        }
    }
}

//! AppState accessor methods
use crate::snapshot::Snapshot;
use crate::ui::elements::Element;
use super::types::ChatMessage;
use std::collections::VecDeque;

const SPINNER_CHARS: &[char] = &['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠹', '⠸', '⠴', '⠼'];
const SPINNER_FRAMES: u32 = 12;

impl AppState {
    // --- Core accessors ---

    pub fn messages(&self) -> &[ChatMessage] {
        &self.chat.messages
    }

    pub fn messages_mut(&mut self) -> &mut Vec<ChatMessage> {
        &mut self.chat.messages
    }

    pub fn input(&self) -> &str {
        &self.input.input
    }

    pub fn cursor_pos(&self) -> usize {
        self.input.cursor_pos
    }

    pub fn set_cursor_pos(&mut self, pos: usize) {
        self.input.cursor_pos = pos;
    }

    pub fn scroll(&self) -> usize {
        self.chat.scroll
    }

    pub fn set_scroll(&mut self, scroll: usize) {
        self.chat.scroll = scroll;
    }

    pub fn streaming(&self) -> bool {
        self.agent.streaming
    }

    pub fn turn_active(&self) -> bool {
        self.agent.turn_active
    }

    pub fn inflight(&self) -> usize {
        self.agent.inflight
    }

    pub fn request_queue(&self) -> &VecDeque<(String, String)> {
        &self.agent.request_queue
    }

    pub fn message_queue(&self) -> &[super::QueuedMessage] {
        &self.agent.message_queue
    }

    pub fn current_request_id(&self) -> Option<&str> {
        self.agent.current_request_id.as_deref()
    }

    pub fn current_action(&self) -> Option<&str> {
        self.agent.current_action.as_deref()
    }

    pub fn at_suggestions(&self) -> Option<&[String]> {
        self.input.at_suggestions.as_deref()
    }

    pub fn at_selected(&self) -> Option<usize> {
        self.input.at_selected
    }

    pub fn all_collapsed(&self) -> bool {
        self.ui.all_collapsed
    }

    pub fn animation_frame(&self) -> u32 {
        self.ui.animation_frame
    }

    pub fn input_flash(&self) -> u8 {
        self.input.input_flash
    }

    pub fn placeholder(&self) -> &str {
        &self.chat.placeholder
    }

    // --- Time & animation ---

    pub fn next_id(&mut self) -> String {
        let id = format!("req.{}", self.agent.next_id);
        self.agent.next_id += 1;
        id
    }

    pub fn thinking_elapsed_secs(&self) -> Option<f64> {
        self.agent.thinking_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn turn_elapsed_secs(&self) -> Option<f64> {
        self.agent.turn_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn tool_elapsed_secs(&self) -> Option<f64> {
        self.agent.tool_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn spinner_frame(&self) -> char {
        SPINNER_CHARS[(self.ui.animation_frame % SPINNER_FRAMES) as usize]
    }

    // --- Dirty tracking ---

    pub fn mark_dirty(&mut self) {
        self.chat.dirty = true;
    }

    pub fn messages_changed(&mut self) {
        self.chat.message_gen = self.chat.message_gen.wrapping_add(1);
        self.chat.dirty = true;
    }

    pub fn cache_generation(&self) -> u64 {
        self.chat.message_gen
    }

    pub fn ensure_fresh(&mut self) {
        if self.chat.dirty && self.chat.message_gen != self.chat.cached_gen {
            self.chat.elements_cache = crate::ui::LazyCache::rebuild(self);
            self.chat.element_count = self.chat.elements_cache.len();
            self.chat.line_counts =
                self.chat.elements_cache.iter().map(|e| e.line_count()).collect();
            self.chat.total_lines = self.chat.line_counts.iter().sum();
            self.chat.cached_gen = self.chat.message_gen;
        }
        self.chat.dirty = false;
    }

    // --- Element cache access ---

    pub fn count(&self) -> usize {
        self.chat.element_count.max(self.chat.elements_cache.len())
    }

    pub fn element_count(&self) -> usize {
        self.chat.element_count
    }

    pub fn total_lines(&self) -> usize {
        self.chat.total_lines
    }

    pub fn elements_cache(&self) -> &[Element] {
        &self.chat.elements_cache
    }

    pub fn tick_animation(&mut self) {
        let mut changed = false;
        if self.agent.turn_active {
            self.ui.animation_frame = self.ui.animation_frame.wrapping_add(1);
            changed = true;
        }
        if self.input.input_flash > 0 {
            self.input.input_flash -= 1;
            changed = true;
        }
        if changed {
            self.chat.dirty = true;
        }
    }

    pub fn is_dirty(&self) -> bool {
        self.chat.dirty
    }
}

//! AppState helper methods
use crate::snapshot::Snapshot;
use super::types::{ChatMessage, Role};

impl AppState {
    // --- Snapshot ---

    pub fn snapshot(&self) -> Snapshot {
        Snapshot {
            elements: self.chat.elements_cache.clone(),
            line_counts: self.chat.line_counts.clone(),
            total_lines: self.chat.total_lines,
            input: self.input.input.clone(),
            cursor_pos: self.input.cursor_pos,
            hint_text: self.hint_text(),
            at_suggestions: self.input.at_suggestions.clone(),
            at_selected: self.input.at_selected,
            turn_active: self.agent.turn_active,
            input_flash: self.input.input_flash,
            placeholder: self.chat.placeholder.clone(),
            spinner_frame: self.spinner_frame(),
            scroll: self.chat.scroll,
            turn_elapsed_secs: self.turn_elapsed_secs(),
            provider: self.current_provider.clone(),
            model: self.current_model.clone(),
            queue_count: self.agent.message_queue.len() + self.agent.request_queue.len(),
        }
    }

    // --- Scroll helpers ---

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.chat.total_lines.saturating_sub(visible_height);
        let scroll = self.chat.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.chat.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.chat.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }

    // --- Token estimation & compaction ---

    pub fn total_tokens(&self) -> usize {
        self.chat
            .messages
            .iter()
            .map(|m| crate::tokens::estimate_tokens(&m.content))
            .sum()
    }

    pub fn compact(&mut self, keep_recent_tokens: usize) -> String {
        use super::types::now;
        let total = self.total_tokens();
        if total <= keep_recent_tokens {
            return format!("Session has {} tokens, no compaction needed", total);
        }
        let mut accumulated = 0usize;
        let mut cut_idx = 0usize;
        for (i, msg) in self.chat.messages.iter().enumerate().rev() {
            accumulated += crate::tokens::estimate_tokens(&msg.content);
            if accumulated >= keep_recent_tokens {
                cut_idx = i;
                break;
            }
        }
        while cut_idx < self.chat.messages.len() {
            match self.chat.messages[cut_idx].role {
                Role::User | Role::Assistant => break,
                _ => cut_idx += 1,
            }
        }
        if cut_idx == 0 {
            return "Cannot compact: all messages are recent".to_string();
        }
        let removed_count = cut_idx;
        self.chat.messages.drain(..cut_idx);
        let summary = format!(
            "[Compacted: {} earlier messages removed, keeping ~{} tokens]",
            removed_count, keep_recent_tokens
        );
        self.chat.messages.insert(
            0,
            ChatMessage {
                role: Role::System,
                content: summary.clone(),
                timestamp: now(),
                id: "compaction".to_string(),
            },
        );
        self.messages_changed();
        summary
    }

    // --- Setters for composed state ---

    pub fn set_streaming(&mut self, val: bool) {
        self.agent.streaming = val;
    }

    pub fn set_turn_active(&mut self, val: bool) {
        self.agent.turn_active = val;
    }

    pub fn set_current_request_id(&mut self, val: Option<String>) {
        self.agent.current_request_id = val;
    }

    pub fn set_thinking_started_at(&mut self, val: Option<std::time::Instant>) {
        self.agent.thinking_started_at = val;
    }

    pub fn set_current_action(&mut self, val: Option<String>) {
        self.agent.current_action = val;
    }

    pub fn set_tool_started_at(&mut self, val: Option<std::time::Instant>) {
        self.agent.tool_started_at = val;
    }

    pub fn set_current_tool_name(&mut self, val: Option<String>) {
        self.agent.current_tool_name = val;
    }

    pub fn thought_seq(&self) -> u64 {
        self.agent.thought_seq
    }

    pub fn thought_seq_increment(&mut self) {
        self.agent.thought_seq += 1;
    }

    pub fn set_intermediate_step_count(&mut self, val: usize) {
        self.agent.intermediate_step_count = val;
    }

    pub fn intermediate_step_count_increment(&mut self) {
        self.agent.intermediate_step_count += 1;
    }

    pub fn set_turn_started_at(&mut self, val: Option<std::time::Instant>) {
        self.agent.turn_started_at = val;
    }

    pub fn set_thought_seq(&mut self, val: u64) {
        self.agent.thought_seq = val;
    }

    pub fn messages_len(&self) -> usize {
        self.chat.messages.len()
    }

    pub fn messages_position<F>(&self, f: F) -> Option<usize>
    where
        F: FnMut(&ChatMessage) -> bool,
    {
        self.chat.messages.iter().position(f)
    }

    pub fn messages_rposition<F>(&self, f: F) -> Option<usize>
    where
        F: FnMut(&ChatMessage) -> bool,
    {
        self.chat.messages.iter().rposition(f)
    }

    pub fn messages_get_mut(&mut self, idx: usize) -> Option<&mut ChatMessage> {
        self.chat.messages.get_mut(idx)
    }

    pub fn messages_remove(&mut self, idx: usize) -> ChatMessage {
        self.chat.messages.remove(idx)
    }

    pub fn messages_insert(&mut self, idx: usize, msg: ChatMessage) {
        self.chat.messages.insert(idx, msg);
    }

    pub fn messages_push(&mut self, msg: ChatMessage) {
        self.chat.messages.push(msg);
    }

    pub fn messages_iter_mut(&mut self) -> impl Iterator<Item = &mut ChatMessage> {
        self.chat.messages.iter_mut()
    }

    pub fn messages_retain<F>(&mut self, f: F)
    where
        F: FnMut(&ChatMessage) -> bool,
    {
        self.chat.messages.retain(f);
    }

    pub fn inflight_decrement(&mut self) {
        self.agent.inflight = self.agent.inflight.saturating_sub(1);
    }

    pub fn set_all_collapsed(&mut self, val: bool) {
        self.ui.all_collapsed = val;
    }

    pub fn set_animation_frame(&mut self, val: u32) {
        self.ui.animation_frame = val;
    }

    pub fn animation_frame_increment(&mut self) {
        self.ui.animation_frame = self.ui.animation_frame.wrapping_add(1);
    }
}

